      /* <flatten type="Javascript"> */
function load$GridGNApprovalRoles(g) {
  g.add_onResponseComplete(on$GridGNApprovalRoles$ResponseComplete);
  g.add_commandEvent(on$GridGNApprovalRoles$ExecuteCommand);
}
function dispose$GridGNApprovalRoles(g) {
  try {g.remove_commandEvent(on$GridGNApprovalRoles$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridGNApprovalRoles$ResponseComplete);} catch (ex) {}
}
function on$GridGNApprovalRoles$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'ImportData':
      show$Form(g, 'GNApprovalRolesImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
function on$GridGNApprovalRoles$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
function show$Form(g, c) {(g._authorize == 1) ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess"));}
/* </flatten> */
